import os
import secrets
import time
from typing import Optional, Dict, Tuple
from datetime import datetime, timedelta
from web3 import Web3
from eth_account.messages import encode_defunct
import hashlib
import hmac


class Web3AuthService:
    def __init__(self, secret_key: Optional[str] = None):
        self.w3 = Web3()
        self.secret_key = secret_key or os.environ.get('AUTH_SECRET_KEY', secrets.token_hex(32))
        self.nonce_store: Dict[str, Tuple[str, float]] = {}
        self.nonce_expiry = 300
        self.rate_limit_store: Dict[str, list] = {}
        self.rate_limit_window = 60
        self.rate_limit_max_attempts = 10
        
    def generate_nonce(self, address: str) -> str:
        address = address.lower()
        
        if not Web3.is_address(address):
            raise ValueError("Invalid Ethereum address")
        
        timestamp = int(time.time())
        random_bytes = secrets.token_bytes(16)
        nonce_data = f"{address}:{timestamp}:{random_bytes.hex()}"
        nonce = hashlib.sha256(nonce_data.encode()).hexdigest()
        
        self.nonce_store[address] = (nonce, time.time())
        
        return nonce
    
    def _verify_nonce(self, address: str, nonce: str) -> bool:
        address = address.lower()
        
        if address not in self.nonce_store:
            return False
        
        stored_nonce, timestamp = self.nonce_store[address]
        
        if time.time() - timestamp > self.nonce_expiry:
            del self.nonce_store[address]
            return False
        
        if not hmac.compare_digest(stored_nonce, nonce):
            return False
        
        del self.nonce_store[address]
        return True
    
    def _check_rate_limit(self, address: str) -> bool:
        address = address.lower()
        current_time = time.time()
        
        if address not in self.rate_limit_store:
            self.rate_limit_store[address] = []
        
        attempts = self.rate_limit_store[address]
        attempts = [t for t in attempts if current_time - t < self.rate_limit_window]
        self.rate_limit_store[address] = attempts
        
        if len(attempts) >= self.rate_limit_max_attempts:
            return False
        
        self.rate_limit_store[address].append(current_time)
        return True
    
    def _validate_message_format(self, message: str, nonce: str, timestamp: int) -> bool:
        if not message or not nonce:
            return False
        
        if len(nonce) != 64:
            return False
        
        current_time = int(time.time())
        if abs(current_time - timestamp) > self.nonce_expiry:
            return False
        
        expected_message = f"Sign this message to authenticate with our service.\n\nNonce: {nonce}\nTimestamp: {timestamp}"
        
        if not hmac.compare_digest(message, expected_message):
            return False
        
        return True
    
    def verify_signature(
        self, 
        message: str, 
        signature: str, 
        expected_address: str,
        nonce: str,
        timestamp: int
    ) -> bool:
        try:
            expected_address = expected_address.lower()
            
            if not Web3.is_address(expected_address):
                return False
            
            if not self._check_rate_limit(expected_address):
                return False
            
            if not self._verify_nonce(expected_address, nonce):
                return False
            
            if not self._validate_message_format(message, nonce, timestamp):
                return False
            
            if not signature.startswith('0x'):
                signature = '0x' + signature
            
            if len(signature) != 132:
                return False
            
            message_hash = encode_defunct(text=message)
            
            recovered_address = self.w3.eth.account.recover_message(
                message_hash,
                signature=signature
            )
            
            recovered_address = recovered_address.lower()
            
            if not hmac.compare_digest(recovered_address, expected_address):
                return False
            
            return True
            
        except Exception as e:
            return False
    
    def create_auth_message(self, nonce: str) -> Tuple[str, int]:
        timestamp = int(time.time())
        message = f"Sign this message to authenticate with our service.\n\nNonce: {nonce}\nTimestamp: {timestamp}"
        return message, timestamp
    
    def authenticate_user(
        self,
        address: str,
        signature: str,
        message: str,
        nonce: str,
        timestamp: int
    ) -> Dict[str, any]:
        try:
            is_valid = self.verify_signature(
                message=message,
                signature=signature,
                expected_address=address,
                nonce=nonce,
                timestamp=timestamp
            )
            
            if not is_valid:
                return {
                    'success': False,
                    'error': 'Invalid signature or authentication failed',
                    'address': None,
                    'token': None
                }
            
            session_token = self._generate_session_token(address)
            
            return {
                'success': True,
                'error': None,
                'address': address.lower(),
                'token': session_token
            }
            
        except Exception as e:
            return {
                'success': False,
                'error': 'Authentication error',
                'address': None,
                'token': None
            }
    
    def _generate_session_token(self, address: str) -> str:
        timestamp = int(time.time())
        random_data = secrets.token_bytes(32)
        token_data = f"{address}:{timestamp}:{random_data.hex()}:{self.secret_key}"
        token = hashlib.sha256(token_data.encode()).hexdigest()
        return token
    
    def cleanup_expired_nonces(self):
        current_time = time.time()
        expired_addresses = [
            addr for addr, (_, timestamp) in self.nonce_store.items()
            if current_time - timestamp > self.nonce_expiry
        ]
        for addr in expired_addresses:
            del self.nonce_store[addr]
    
    def cleanup_rate_limits(self):
        current_time = time.time()
        for address in list(self.rate_limit_store.keys()):
            attempts = [
                t for t in self.rate_limit_store[address]
                if current_time - t < self.rate_limit_window
            ]
            if attempts:
                self.rate_limit_store[address] = attempts
            else:
                del self.rate_limit_store[address]


